window.AV_SEARCH = [{"id":"home","title":"Home — Repository overview","section":"","sectionLabel":"AquaVision","url":"index.html","provenance":"","flags":"","text":"home dashboard overview provenance legend awaiting data sections aquavision omnidrone knowledge repository"},{"id":"meta","title":"00 Meta & Schemas","section":"meta","sectionLabel":"Meta & Schemas","url":"sections/meta.html","provenance":"","flags":"","text":"Schema registry, glossary, data dictionary, changelog. Read this to understand every other file. engineer thesis_committee"},{"id":"company","title":"01 Company & Identity","section":"company","sectionLabel":"Company & Identity","url":"sections/company.html","provenance":"","flags":"","text":"Who AquaVision is: profile, brand system, mission, team structure, milestone roadmap. investor public"},{"id":"problem","title":"02 Problem Space","section":"problem","sectionLabel":"Problem Space","url":"sections/problem.html","provenance":"","flags":"","text":"The aquaculture and fisheries problems the OmniDrone addresses, taxonomised, evidenced, and costed. investor thesis_committee farmer"},{"id":"market","title":"03 Market & Competition","section":"market","sectionLabel":"Market & Competition","url":"sections/market.html","provenance":"","flags":"","text":"Industry statistics, TAM/SAM/SOM, competitor teardown, customer personas, SWOT and Porter analysis. investor"},{"id":"solution","title":"04 Solution & ConOps","section":"solution","sectionLabel":"Solution & ConOps","url":"sections/solution.html","provenance":"","flags":"","text":"What the OmniDrone does, the value proposition, the use cases, and the concept of operations. investor farmer engineer"},{"id":"hardware","title":"05 Hardware Engineering","section":"hardware","sectionLabel":"Hardware Engineering","url":"sections/hardware.html","provenance":"","flags":"","text":"Airframe, propulsion, reeled probe winch, sensor payload, carriage/ejection system, power budget, dock, BOM. engineer thesis_committee"},{"id":"software","title":"06 Software, AI & Digital Twin","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"sections/software.html","provenance":"","flags":"","text":"System architecture, data pipeline, ML model cards, digital twin spec, API, telemetry schema, dashboard spec. engineer thesis_committee"},{"id":"research","title":"07 Research Corpus","section":"research","sectionLabel":"Research Corpus","url":"sections/research.html","provenance":"","flags":"","text":"Literature review, thematic related-studies collections, full bibliography with links, research gaps, theoretical framework, methodology. thesis_committee"},{"id":"operations","title":"08 Operations & Safety","section":"operations","sectionLabel":"Operations & Safety","url":"sections/operations.html","provenance":"","flags":"","text":"Deployment playbook, maintenance, risk register (FMEA), training and certification. engineer farmer"},{"id":"compliance","title":"09 Regulatory & Compliance","section":"compliance","sectionLabel":"Regulatory & Compliance","url":"sections/compliance.html","provenance":"","flags":"","text":"Aviation law, fisheries law, water quality standards, biosecurity, data ethics and privacy. investor thesis_committee engineer"},{"id":"business","title":"10 Business Model","section":"business","sectionLabel":"Business Model","url":"sections/business.html","provenance":"","flags":"","text":"Business model canvas, pricing, unit economics, financial projections, funding ask, go-to-market. investor"},{"id":"impact","title":"11 Impact","section":"impact","sectionLabel":"Impact","url":"sections/impact.html","provenance":"","flags":"","text":"SDG alignment, environmental impact, social and economic impact. investor public thesis_committee"},{"id":"datasets","title":"12 Datasets & Charts","section":"datasets","sectionLabel":"Datasets & Charts","url":"sections/datasets.html","provenance":"","flags":"","text":"Chart-ready payloads, KPI definitions, sample telemetry, sample digital twin state. engineer"},{"id":"pitch","title":"13 Pitch & Thesis Kit","section":"pitch","sectionLabel":"Pitch & Thesis Kit","url":"sections/pitch.html","provenance":"","flags":"","text":"Deck outline, elevator pitches at three lengths, objection handling, thesis chapter outline. investor thesis_committee"},{"id":"schema-registry","title":"AquaVision Knowledge Repository — Schema Registry","section":"meta","sectionLabel":"Meta & Schemas","url":"files/schema-registry.html","provenance":"","flags":"S","text":"schema-registry • aquavision knowledge repository — schema registry • 1.0.0 • 2026-07-17 • defines the shape of every recurring object in this repository so that a consuming webpage can render any file generically. these are json schema (draft 2020-12) fragments plus prose notes. • kebab-case, globally unique within the repository, permanent. labels may be edited freely; ids may not. • si unless the field name states otherwise. currency fields always carry an explicit iso-4217 `currency` sibling. never store a bare number for money. • iso 8601. full dates as yyyy-mm-dd. years as integers. ranges as {start, end}. • use null for 'known to be absent'. use the string 'unknown' for 'we have not determined this'. never use 0 as a stand-in for missing. • any factual claim carries `citation_ids: ["},{"id":"glossary","title":"Glossary — Aquaculture, Fisheries, Remote Sensing, and Systems Terms","section":"meta","sectionLabel":"Meta & Schemas","url":"files/glossary.html","provenance":"","flags":"","text":"glossary • glossary — aquaculture, fisheries, remote sensing, and systems terms • 1.0.0 • 2026-07-17 • controlled vocabulary for the whole repository and for the thesis. where a term has a contested definition, both readings are given. terms are grouped for ui filtering but the flat `terms[]` array is authoritative. • aquaculture • water_quality • biology_health • remote_sensing • uav_systems • data_ai • business • regulatory • aquaculture • aquaculture • the farming of aquatic organisms — fish, molluscs, crustaceans, and aquatic plants — involving intervention in the rearing process to enhance production, such as regular stocking, feeding, and protection from predators. implies individual or corporate ownership of the stock being cultivated, which is the line that separates it from captur"},{"id":"data-dictionary","title":"Data Dictionary — Canonical Field and Variable Definitions","section":"meta","sectionLabel":"Meta & Schemas","url":"files/data-dictionary.html","provenance":"","flags":"","text":"data-dictionary • data dictionary — canonical field and variable definitions • 1.0.0 • 2026-07-17 • defines every measured variable the omnidrone produces, its units, its valid range, its storage type, and its interpretation rules. this is the contract between the flight hardware, the ingestion pipeline, the digital twin, and the dashboard. if a variable is not in this file, it does not exist. • do_mgl • dissolved oxygen • mg/l • float • optical_do • master safety variable. interpret against species threshold and against time of day — a 5 mg/l reading at 15:00 is a very different fact from 5 mg/l at 05:00, because the afternoon reading is near the diel maximum and implies a dangerous pre-dawn minimum. • do_saturation_pct • do_deficit • below • boyd-water-quality-2020 • igs-do-aquaculture-2"},{"id":"changelog","title":"Repository Changelog","section":"meta","sectionLabel":"Meta & Schemas","url":"files/changelog.html","provenance":"","flags":"","text":"changelog • repository changelog • 1.0.0 • 2026-07-17 • keep a changelog 1.1.0 conventions, expressed as json. • keep-a-changelog • 1.0.0 • 2026-07-17 • aquavision founding team (drafted with ai assistance) • initial construction of the omnidrone knowledge repository from the founding concept description. • full 14-section repository skeleton with manifest-driven index for webpage consumption. • schema registry and data dictionary establishing the provenance discipline used throughout. • problem space: taxonomy, stakeholder pain points, evidenced incident case studies, cost-of-inaction model. • market: industry statistics sourced to fao sofia 2024, tam/sam/som model, competitor teardown. • hardware: airframe, probe winch, sensor payload, carriage/ejection, power budget, dock, indicative bo"},{"id":"company-profile","title":"AquaVision — Company Profile","section":"company","sectionLabel":"Company & Identity","url":"files/company-profile.html","provenance":"assumption","flags":"","text":"company-profile • aquavision — company profile • 1.0.0 • 2026-07-17 • assumption • corporate facts below are the founding team's stated intent. fields marked `awaiting_confirmation` must be filled from registration documents before any external use. • awaiting_confirmation • aquavision • fisheries • aquaculture • technology • awaiting_confirmation • awaiting_confirmation • awaiting_confirmation • philippines (specific locality awaiting_confirmation) • pre-seed / concept-to-prototype • awaiting_confirmation • awaiting_confirmation • aquavision builds the omnidrone — an autonomous aerial platform that flies to fish farms, drops a reeled probe to profile the water column, scans the surface for trouble, delivers feed and treatments, and streams it all into a live digital twin of the pond. • fi"},{"id":"brand-identity","title":"AquaVision — Brand & Design System","section":"company","sectionLabel":"Company & Identity","url":"files/brand-identity.html","provenance":"verified_external","flags":"","text":"brand-identity • aquavision — brand & design system • 1.0.0 • 2026-07-17 • verified_external • colour values are sampled by eye from the supplied logo assets and should be replaced with the exact values from the original vector source when available. treat them as close approximations, not the brand standard. • photo_2026-07-17_13-51-55.jpg • mark above wordmark 'aquavision' with the descriptor line 'fisheries • aquaculture • technology' beneath. • primary lockup. default for decks, documents, and the site header. • photo_2026-07-17_13-52-22.jpg • the 'a' monogram formed from a triangular peak, with a stylised fish nested inside and a wave sweeping beneath. • favicon, app icon, drone fuselage badge, and any context under ~48 px where the wordmark would be illegible. • the 'a' of aquavision"},{"id":"team-structure","title":"Team Structure & Capability Map","section":"company","sectionLabel":"Company & Identity","url":"files/team-structure.html","provenance":"assumption","flags":"","text":"team-structure • team structure & capability map • 1.0.0 • 2026-07-17 • assumption • this file describes the roles this venture requires, not people it has. every `holder` field is deliberately null. fill them with real names and real, verifiable backgrounds. do not let generated placeholder biographies reach an investor — fabricated team credentials are the fastest way to destroy a fundraise and, depending on jurisdiction, a securities problem. • ceo • chief executive / commercial lead • aquaculture technology does not sell itself. someone has to sit on a dike at 5 a.m. with a farmer who has been burned by a previous gadget vendor and earn the pilot. • aquaculture sector relationships • fundraising • regulatory navigation with caap and bfar • pricing against loss avoidance rather than fea"},{"id":"milestones-roadmap","title":"Development Roadmap & Milestones","section":"company","sectionLabel":"Company & Identity","url":"files/milestones-roadmap.html","provenance":"modeled_projection","flags":"","text":"milestones-roadmap • development roadmap & milestones • 1.0.0 • 2026-07-17 • modeled_projection • low • this is a plan, not a forecast. hardware timelines slip; aquaculture hardware timelines slip more, because the validation season is set by the weather and the fish, not by the sprint board. durations are stated as ranges and the gates are stated as evidence, not as dates. an investor should read the gates, not the calendar. • p0 • phase 0 — definition • convert the concept into a defensible, evidenced specification and prove the science is sound before spending money on hardware. • literature review and research corpus (this repository). • requirements baseline with traceability to stakeholder needs. • mass, power, and payload budget — the go/no-go arithmetic on whether the vehicle can e"},{"id":"problem-statement","title":"Problem Statement","section":"problem","sectionLabel":"Problem Space","url":"files/problem-statement.html","provenance":"","flags":"","text":"problem-statement • problem statement • 1.0.0 • 2026-07-17 • aquaculture operators make decisions worth their entire annual income about a three-dimensional, fast-changing chemical environment they cannot see, using a handful of surface observations taken at the safest time of day. • a fish farmer's stock lives in a water column that stratifies, deoxygenates, blooms, and overturns on timescales of hours. the farmer's instruments — where they exist at all — measure one point, at the surface, when someone happens to be there. the gap between the resolution at which the water actually behaves and the resolution at which it is observed is where mass mortality events live. every documented fish kill is, at bottom, a monitoring failure as much as a water quality failure: the conditions developed"},{"id":"problem-taxonomy","title":"Problem Taxonomy — The Full Space of Aquaculture & Fisheries Problems","section":"problem","sectionLabel":"Problem Space","url":"files/problem-taxonomy.html","provenance":"","flags":"","text":"problem-taxonomy • problem taxonomy — the full space of aquaculture & fisheries problems • 1.0.0 • 2026-07-17 • an exhaustive map of problems in the field, classified by whether the omnidrone addresses them. the classification is the point: a technology repository that lists only the problems its product solves is a brochure. this file exists to show the committee and the investor that the team knows the boundaries of its own solution. • the omnidrone directly and substantially addresses this. this is what we are for. • the omnidrone contributes meaningfully but does not solve it. honest framing required in any claim. • the platform generates data relevant to this, but solving it needs other actors or tools. • real problem in the field. we do not touch it. listed so nobody thinks we forgot"},{"id":"stakeholder-pain-points","title":"Stakeholder Map & Pain Points","section":"problem","sectionLabel":"Problem Space","url":"files/stakeholder-pain-points.html","provenance":"assumption","flags":"","text":"stakeholder-pain-points • stakeholder map & pain points • 1.0.0 • 2026-07-17 • assumption • low • these pain points are inferred from literature and from the structure of the industry. they are not from interviews, because no interviews have been conducted. every entry is a hypothesis with a question attached that phase 0 discovery must answer. a stakeholder map built from desk research describes the industry an outsider imagines. • smallholder-cage-operator • smallholder cage operator • operates a handful of cages in a lake, often financed by debt against the coming harvest. frequently the family's sole income. • low • very high • aspirationally • a single kill event destroys a year of income and leaves the debt intact. • existential • cannot afford monitoring equipment, and would not hav"},{"id":"incident-case-studies","title":"Documented Incident Case Studies — Evidence Base","section":"problem","sectionLabel":"Problem Space","url":"files/incident-case-studies.html","provenance":"verified_external","flags":"","text":"incident-case-studies • documented incident case studies — evidence base • 1.0.0 • 2026-07-17 • verified_external • real, reported fish kill and water quality incidents used as the evidence base for the problem statement. these are other people's losses, documented by journalists and scientists. treat them with the seriousness they deserve — each figure below is somebody's harvest. • details below are drawn from search-result summaries of news reports and published studies. every entry carries a `verification_status`. before any of these appear in a thesis or a deck, open the primary source and confirm the figure. news reporting of fish kill tonnages is frequently revised upward or downward in later reports, and citing a superseded figure is an easy and avoidable error. • taal-fishkill-202"},{"id":"cost-of-inaction","title":"Cost of Inaction — Loss Model","section":"problem","sectionLabel":"Problem Space","url":"files/cost-of-inaction.html","provenance":"modeled_projection","flags":"","text":"cost-of-inaction • cost of inaction — loss model • 1.0.0 • 2026-07-17 • modeled_projection • low • this is a model, not a measurement. every number below is either a sourced external statistic (tagged) or an assumption the authors invented (tagged). its purpose is to make the loss structure explicit and attackable — not to prove a market. if you present this as evidence of demand, you will be caught, because the assumptions are visible and several of them are shaky. the correct use is: 'here is our model, here are the assumptions, tell us which one you think is wrong.' that framing wins meetings. 'our research shows php x million' loses them. • catastrophic-mortality • catastrophic mortality events • mass fish kills. sudden, total or near-total loss of standing stock in affected units. • h"},{"id":"industry-statistics","title":"Industry Statistics — Global & Regional Aquaculture and Fisheries","section":"market","sectionLabel":"Market & Competition","url":"files/industry-statistics.html","provenance":"verified_external","flags":"","text":"industry-statistics • industry statistics — global & regional aquaculture and fisheries • 1.0.0 • 2026-07-17 • verified_external • fao, the state of world fisheries and aquaculture (sofia) 2024, reporting 2022 data. • fao-sofia-2024 • values in usd as published by fao. no inflation adjustment applied. • sofia 2024 reports 2022 data — a two-year lag is normal for this dataset. as of this repository's date (july 2026), sofia 2026 may be available and would supersede these figures. check before using in a submission. citing a superseded flagship report is a small error that signals a large carelessness. • total-production-2022 • total global fisheries and aquaculture production • million tonnes • a 4.4 percent increase from 2020, and a record high. • fao-sofia-2024 • verified_external • aquac"},{"id":"market-sizing","title":"Market Sizing — TAM / SAM / SOM","section":"market","sectionLabel":"Market & Competition","url":"files/market-sizing.html","provenance":"modeled_projection","flags":"","text":"market-sizing • market sizing — tam / sam / som • 1.0.0 • 2026-07-17 • modeled_projection • low • this file contains no market size number, and that is deliberate. • a defensible bottom-up market size requires the number of aquaculture operations in the target geography, their size distribution, and their existing spend on monitoring and inputs. we have none of those. the bfar philippine fisheries profile has them; we have not obtained it. • we could take fao's usd 312.8 billion global aquaculture output, apply an invented 'technology penetration rate' of 2 percent, and present a usd 6.3 billion tam. it would look professional. it would be meaningless, because the 2 percent would be pulled from nothing and the whole number would inherit its arbitrariness. every experienced investor has see"},{"id":"competitive-landscape","title":"Competitive Landscape","section":"market","sectionLabel":"Market & Competition","url":"files/competitive-landscape.html","provenance":"assumption","flags":"","text":"competitive-landscape • competitive landscape • 1.0.0 • 2026-07-17 • assumption • low • this file describes competitor categories and the competitive logic. named vendors are deliberately omitted where we have not verified their current offering, and pricing is marked unknown rather than guessed. a competitive analysis containing invented competitor pricing is worse than no competitive analysis — the one thing an investor can trivially check is whether you described a competitor correctly, and getting it wrong destroys your credibility on everything they cannot check. • doing nothing • the overwhelming majority • it is free, it is what the farmer already does, it requires no training, no charging, no trust in a stranger's algorithm, and it has worked well enough that the farm still exists."},{"id":"customer-personas","title":"Customer Segments & Personas","section":"market","sectionLabel":"Market & Competition","url":"files/customer-personas.html","provenance":"assumption","flags":"","text":"customer-personas • customer segments & personas • 1.0.0 • 2026-07-17 • assumption • speculative • these personas are constructed from industry literature and structural reasoning. they are not derived from interviews, because none have been conducted. they are hypotheses to falsify in phase 0, and they are named as fictional composites so nobody mistakes them for research subjects. personas built without fieldwork tend to describe the customer the founders wish existed. • persona-mang-tonio • mang tonio — smallholder cage operator • the one who needs it most and can afford it least • 6-10 tilapia cages in a lake, ~1 cycle per 5-6 months, financed on credit against harvest • taal lake or laguna de bay • twenty years on this water. reads the wind, the colour, and the way the fish come up be"},{"id":"swot-porter","title":"Strategic Analysis — SWOT, Porter's Five Forces, PESTEL","section":"market","sectionLabel":"Market & Competition","url":"files/swot-porter.html","provenance":"assumption","flags":"","text":"swot-porter • strategic analysis — swot, porter's five forces, pestel • 1.0.0 • 2026-07-17 • assumption • three standard frameworks applied honestly. the value of a swot is entirely in whether the weaknesses are real; a swot with four strengths and one polite weakness is a self-portrait, not an analysis. • the reeled probe is a genuine architectural differentiator • depth-resolved chemistry from an aircraft is rare, and depth is where the killing mechanism lives. nobody else in the accessible market pairs it with same-sortie imaging. • high • probe-calibrated imagery closes a real scientific gap • uncalibrated indices produce time series that are not comparable across days. carrying the ground truth on the same vehicle is a clean answer to a problem the literature identifies repeatedly. • "},{"id":"solution-overview","title":"Solution Overview — The OmniDrone System","section":"solution","sectionLabel":"Solution & ConOps","url":"files/solution-overview.html","provenance":"design_target","flags":"","text":"solution-overview • solution overview — the omnidrone system • 1.0.0 • 2026-07-17 • design_target • the omnidrone is an autonomous multirotor that launches from a shore-side dock, flies a planned route across a fish farm, and at each station lowers a multiparameter sonde on a powered winch to profile the water column from surface to bottom. while it hovers, a calibrated multispectral and thermal payload images the surrounding water, and the probe's in-situ chemistry calibrates that imagery into real concentrations rather than relative indices. a carriage and ejection system dispenses feed, lime, conditioners, or treatments to specific coordinates. everything streams to the aquavision platform, which fuses point profiles with area imagery, drives a digital twin of the water body, and surfac"},{"id":"value-proposition","title":"Value Proposition","section":"solution","sectionLabel":"Solution & ConOps","url":"files/value-proposition.html","provenance":"modeled_projection","flags":"","text":"value-proposition • value proposition • 1.0.0 • 2026-07-17 • modeled_projection • low • osterwalder-vpd-2014 • mapped against the beachhead persona (marissa, commercial farm operations manager). a canvas mapped against 'the customer' in general is mapped against nobody. • hit the survival and fcr targets this cycle • functional • critical • explain performance variance to the owner • social • high • keep the electricity bill defensible • functional • high • pass the certification audit without a fire drill • functional • medium • not be the manager on duty when the fish die • emotional • high • cannot observe 40 units personally • high • aeration runs on a schedule nobody can justify • high • feed is 60 percent of cost with no feedback loop • high • innovasea-fcr-guide • finds out about a "},{"id":"use-cases","title":"Use Cases","section":"solution","sectionLabel":"Solution & ConOps","url":"files/use-cases.html","provenance":"design_target","flags":"","text":"use-cases • use cases • 1.0.0 • 2026-07-17 • design_target • each use case traces to a problem id in problem-taxonomy.json and generates requirements in the hardware and software files. a use case that traces to nothing is a feature someone wanted. • uc-01-dawn-profile • the pre-dawn profile • must • prob-diel-sampling-bias • prob-blindness-at-depth • wq-do-depletion • system (autonomous), overseen by farm manager • scheduled, 04:30 local • dock has charge • weather within envelope • airspace clear • dock opens, drone launches on the stored route. • transits to station 1, establishes a stable hover at profiling altitude. • winch pays out; sonde descends at controlled rate, sampling continuously. • descends to configured depth or until bottom proximity is detected. • recovers, transits to s"},{"id":"mission-profiles","title":"Mission Profiles","section":"solution","sectionLabel":"Solution & ConOps","url":"files/mission-profiles.html","provenance":"design_target","flags":"","text":"mission-profiles • mission profiles • 1.0.0 • 2026-07-17 • design_target • low • every duration, distance, and station count below is a design target derived from the energy budget in power-energy-budget.json, which is itself a paper model with no flight data behind it. these are the missions we are designing toward, not missions that have been flown. if the energy budget does not close in phase 0, these profiles change or the concept changes. do not put these numbers in a customer proposal. • mp-01-dawn-sweep • dawn sweep • capture the diel dissolved oxygen minimum across the array. the flagship mission. • scheduled, ~60-90 minutes before sunrise • probe • rgb • no dispensing load • mass. dropping the hopper buys endurance, and nothing is dispensed at 04:30 anyway. configuring the payload"},{"id":"concept-of-operations","title":"Concept of Operations (ConOps)","section":"solution","sectionLabel":"Solution & ConOps","url":"files/concept-of-operations.html","provenance":"design_target","flags":"","text":"concept-of-operations • concept of operations (conops) • 1.0.0 • 2026-07-17 • design_target • follows the spirit of ieee 1362 conops structure. describes how the system is used in the field, by whom, under what authority. • ieee-1362 • tropical inland or brackish water body. fish cages or ponds. shore access via dike or bank. grid power unreliable or absent. cellular coverage intermittent. monsoon season for roughly half the year. ambient temperature 25-35 c, humidity high, water corrosive and biologically active. • not a research site. a working farm, operated by people with other jobs to do, where the drone is the least important thing happening that day. if the system requires attention, it will not get it. • attended vlos • certificated remote pilot present, aircraft in visual line of "},{"id":"omnidrone-specifications","title":"OmniDrone — System Specification","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/omnidrone-specifications.html","provenance":"design_target","flags":"","text":"omnidrone-specifications • omnidrone — system specification • 1.0.0 • 2026-07-17 • design_target • low • no hardware exists. every value in this file is a design target or a requirement, not a measurement. nothing has been built, weighed, or flown. the render in the repository root is an industrial design study and is not dimensionally authoritative. where the render and this specification disagree, both need reconciling — neither is validated. • the probe is the product • every trade-off resolves in favour of getting a good sonde to depth reliably. the camera is valuable; the winch is existential. • mass is the enemy • multirotor payload fraction is brutal and unforgiving. every gram of feature costs endurance, and endurance is already our weakest axis against every competitor. • configur"},{"id":"airframe-propulsion","title":"Airframe & Propulsion","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/airframe-propulsion.html","provenance":"design_target","flags":"","text":"airframe-propulsion • airframe & propulsion • 1.0.0 • 2026-07-17 • design_target • low • design targets only. no airframe exists. component masses are placeholders pending a real vendor survey. • quadrotor, x-configuration, ducted rotors • the supplied render shows four shrouded rotors, a central fuselage, twin ventral pods, a forward gimbal, and a sprawled quadrupod gear with wide feet. • the render is an industrial design study. rotor diameter, arm length, and pod volume in the image have not been validated against this specification. do not scale from the image. • hexarotor • motor-out redundancy — genuinely important over water where a failure means loss of aircraft. • more mass, more cost, more drag. • should be seriously reconsidered. over water, with no forced-landing option, single"},{"id":"probe-winch-subsystem","title":"Reeled Probe & Winch Subsystem","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/probe-winch-subsystem.html","provenance":"design_target","flags":"","text":"probe-winch-subsystem • reeled probe & winch subsystem • 1.0.0 • 2026-07-17 • design_target • low • existential — if this does not work, the product is a camera and the company has no defensible position. • every other subsystem on this aircraft can be bought. airframes, cameras, flight controllers, and dispensers are all commodities. the powered winch delivering a sonde to depth from a hovering aircraft, thousands of times, unattended, in a fouling tropical lake full of nets and ropes, is the thing that does not exist off the shelf. it is simultaneously our only real moat and our highest technical risk. those two facts are the same fact. • a motorised spool pays out a combined strength/signal tether carrying a multiparameter sonde from the aircraft's ventral centre-line to a commanded dep"},{"id":"sensor-payload","title":"Sensor Payload — Imaging & Remote Sensing","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/sensor-payload.html","provenance":"design_target","flags":"","text":"sensor-payload • sensor payload — imaging & remote sensing • 1.0.0 • 2026-07-17 • design_target • medium • confidence is higher here than elsewhere in hardware because uav multispectral water sensing is a mature, well-documented literature. we are borrowing established methods rather than inventing them — which is exactly what a startup should do outside its core novelty. • the camera alone produces indices. indices are relative numbers that cannot be compared across days, sites, or illumination conditions. the probe converts indices into concentrations. neither half is a product; together they are. • multispectral • multispectral camera • chlorophyll, turbidity, cdom, and water masking across the whole water body. • multispectral is the practical trade point: enough bands for the band-rat"},{"id":"carriage-ejection-system","title":"Carriage & Ejection System","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/carriage-ejection-system.html","provenance":"design_target","flags":"","text":"carriage-ejection-system • carriage & ejection system • 1.0.0 • 2026-07-17 • design_target • low • two independent analyses in this repository — the mass budget in omnidrone-specifications.json and the mission economics in mission-profiles.json — arrived separately at the same conclusion: this subsystem cannot viably deliver bulk grow-out feed. • a commercial cage takes tens of kilograms per feeding. this aircraft's total useful payload target is 1.8 kg, and that budget is already spent on the probe and the cameras. meanwhile a person in a boat moves a 25 kg sack in one trip at effectively zero marginal cost. we would need dozens of sorties and dozens of battery cycles to do what one person does before breakfast. • reposition this subsystem as a precision treatment delivery system, not a f"},{"id":"power-energy-budget","title":"Power & Energy Budget","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/power-energy-budget.html","provenance":"design_target","flags":"","text":"power-energy-budget • power & energy budget • 1.0.0 • 2026-07-17 • design_target • low • this is a paper model built on assumed efficiencies and assumed component power draws. it has not been validated against any hardware. its purpose is to show whether the mission profiles are plausible and to identify what must be measured. treat the method as the deliverable and every number as a placeholder. • hovering is expensive, and our unique value requires hovering. • a multirotor in hover burns power continuously just to stay up. forward flight is meaningfully more efficient because the rotors work in translational lift. our profiling missions are hover-dominated — the aircraft sits still while the winch does its slow work. so the missions that deliver our only defensible capability are also ou"},{"id":"docking-station","title":"OmniDock — Automated Docking Station","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/docking-station.html","provenance":"design_target","flags":"","text":"docking-station • omnidock — automated docking station • 1.0.0 • 2026-07-17 • design_target • low • four of the system's five distinguishing claims depend on the dock, not the aircraft. it is treated in most drone pitches as an accessory. here it is the thing that makes the product a product. • we measure the pre-dawn dissolved oxygen minimum • autonomous launch. a drone that needs a human to launch it will never fly at 04:30, which means it only ever measures the safest hour of the day — precisely the failure it was built to fix. • our probe fouls less than a moored buoy • the dock rinse cycle. without it we are just a slower buoy with worse uptime. • our multispectral time series is comparable across days • the calibrated reflectance panel living in the dock. without it, every survey is "},{"id":"bill-of-materials","title":"Indicative Bill of Materials","section":"hardware","sectionLabel":"Hardware Engineering","url":"files/bill-of-materials.html","provenance":"assumption","flags":"","text":"bill-of-materials • indicative bill of materials • 1.0.0 • 2026-07-17 • assumption • speculative • no component has been sourced. no supplier has been contacted. no price has been quoted. every figure below is an order-of-magnitude placeholder based on general knowledge of component categories. the correct use of this file is as a structure to fill in during phase 0 vendor engagement, and as an honest statement of what we do not know. any bom cost that reaches an investor deck must come from real quotes. a fabricated bom is the fastest way to build a financial model that is wrong at the foundation, and every number downstream inherits the error. • usd • prototype quantity (1-10 units). volume pricing is a different exercise entirely and should not be assumed from these. • airframe & propul"},{"id":"system-architecture","title":"System Architecture","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/system-architecture.html","provenance":"design_target","flags":"","text":"system-architecture • system architecture • 1.0.0 • 2026-07-17 • design_target • offline is the normal case, not the exception • rural aquaculture sites lose connectivity routinely. every layer must function with the link down and reconcile when it returns. a system that assumes the cloud is a system that fails on the day it matters. • ai-aqua-review-2024 • measurements and predictions live in separate namespaces • the moment a model output can be mistaken for an observation, the dataset is permanently compromised and every downstream analysis is suspect. • raw data is immutable • corrections are new records referencing the original. never overwrite a measurement. • the edge decides what matters; the cloud decides what it means • inference and data reduction on board. training, twin simula"},{"id":"data-pipeline","title":"Data Pipeline","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/data-pipeline.html","provenance":"design_target","flags":"","text":"data-pipeline • data pipeline • 1.0.0 • 2026-07-17 • design_target • the processing path from sensor to decision. stages are ordered; each stage's failure behaviour is specified, because in a monitoring system a silent pipeline failure is worse than a loud one. • a monitoring system that fails silently is worse than no monitoring system, because someone is relying on it. every stage below must fail loudly or degrade visibly. there is no acceptable silent failure anywhere in this pipeline. • acquisition • edge — aircraft • read sensors, timestamp utc, tag with depth from the pressure transducer, tag with position and accuracy. • sensor fault flags the channel and continues. the sortie is not aborted for one dead channel — a profile with seven good channels is worth having. • a fouled sensor"},{"id":"ai-ml-models","title":"AI / ML Model Cards","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/ai-ml-models.html","provenance":"design_target","flags":"","text":"ai-ml-models • ai / ml model cards • 1.0.0 • 2026-07-17 • design_target • follows the model cards convention (mitchell et al., 2019). every card carries an out_of_scope_use field, because a model card without one is marketing. • mitchell-model-cards-2019 • no model has been trained. no model has been evaluated. every `performance` field below is null and every `target_performance` field is an aspiration. these are specifications for models we intend to build, written before the data exists, so that the evaluation criteria are fixed before anyone has an incentive to move them. • the order in which these models ship is a safety decision, not a product decision. • the models are ordered below from 'safe to be wrong' to 'dangerous to be wrong'. a misclassified piece of debris costs a farmer th"},{"id":"digital-twin","title":"PondTwin — Digital Twin Specification","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/digital-twin.html","provenance":"design_target","flags":"","text":"digital-twin • pondtwin — digital twin specification • 1.0.0 • 2026-07-17 • design_target • low • a digital twin is a virtual representation kept synchronised with a physical system by live sensor data, running a model of that system's behaviour, capable of answering counterfactual questions. • a dashboard shows what happened. a twin runs a model and can answer 'what if'. if our pondtwin cannot answer 'what happens to do at cage 4 if i run the aerators for six hours', it is a 3d dashboard and we should call it that. • 'digital twin' is used loosely enough in industry to mean nothing at all — often just a rendered model with live numbers on it. a thesis that adopts the loose usage has conceded its own contribution. defend the strict definition or drop the term. • sciencedirect-dt-aiot-2023 "},{"id":"telemetry-schema","title":"Telemetry & Data Schema","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/telemetry-schema.html","provenance":"design_target","flags":"","text":"telemetry-schema • telemetry & data schema • 1.0.0 • 2026-07-17 • design_target • the wire and storage format for everything the omnidrone produces. this is the contract between aircraft, dock, cloud, twin, and dashboard. field definitions resolve against data-dictionary.json; do not duplicate semantics here. • utc always, rfc 3339, millisecond precision. local time is a presentation concern. storing local time would destroy the diel analysis the first time a site crosses a dst or timezone boundary — and the diel analysis is the product. • every measurement carries a qc flag at source. unflagged data is untrusted data. • every position carries a horizontal accuracy estimate. a position without an error bar cannot answer whether two profiles are at the same station. • model outputs live in "},{"id":"api-specification","title":"API Specification","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/api-specification.html","provenance":"design_target","flags":"","text":"api-specification • api specification • 1.0.0 • 2026-07-17 • design_target • design intent. no api is implemented. paths and shapes are indicative and will change on contact with a real client. • rest over https, json. boring on purpose. there is nothing in this domain that justifies a novel protocol. • read-heavy. the dashboard and the webpage consuming this repository are the primary clients. • every response that contains a number carries its provenance and its qc status. an api that returns bare numbers invites clients to render them as facts. • tenant isolation is enforced at the api boundary, not in the client. a client bug must not be able to expose farm b's data to farm a. • uncertainty is never optional in a response. if a client wants a scalar without an error bar, they can disca"},{"id":"dashboard-spec","title":"Dashboard Specification","section":"software","sectionLabel":"Software, AI & Digital Twin","url":"files/dashboard-spec.html","provenance":"design_target","flags":"","text":"dashboard-spec • dashboard specification • 1.0.0 • 2026-07-17 • design_target • the dashboard must be an answer, not an analytics tool. • the user is a farm manager at 05:30 who has forty other things to do today. she does not want to explore a dataset. she wants to know whether her fish are in danger and what to do about it. every analytics feature we add is a question we have failed to answer for her. • can she get the answer in under five seconds, on a phone, in sunlight, half awake? if not, we have built a tool for ourselves and called it a product. • everything else — the profiles, the maps, the history — lives one level down, for the days when she wants to understand rather than decide. that layer is genuinely valuable and it must not be the front door. • one line per site: is anythi"},{"id":"literature-review","title":"Literature Review — Synthesis","section":"research","sectionLabel":"Research Corpus","url":"files/literature-review.html","provenance":"verified_external","flags":"","text":"literature-review • literature review — synthesis • 1.0.0 • 2026-07-17 • verified_external • the narrative synthesis across the thematic study collections. written to be adapted into a thesis chapter 2. the thematic files hold the individual study records; this file holds the argument. • every claim here traces to references-bibliography.json, where zero sources have been opened and verified. this synthesis is built on search-result summaries. it is a credible map of the literature and a plan for reading it — it is not yet a literature review. read the sources before submitting this. • a literature review should build an argument, not list papers. this is the argument. • aquaculture is now the majority of aquatic animal production, and it is intensifying. • fao sofia 2024: aquaculture surp"},{"id":"references-bibliography","title":"Consolidated Bibliography","section":"research","sectionLabel":"Research Corpus","url":"files/references-bibliography.html","provenance":"","flags":"","text":"references-bibliography • consolidated bibliography • 1.0.0 • 2026-07-17 • every citation_id used anywhere in this repository resolves here. entries carry a verification_status that must be read before use. • most entries below carry verification_status: cited_from_search_result. that means the bibliographic details came from a search engine's summary and nobody has opened the source. • author lists may be incomplete or wrong. • years may be the publication year, the online-first year, or the accessed year — these differ and reviewers notice. • volume, issue, and page numbers are frequently absent or wrong. • the finding attributed to the source may be a paraphrase of a paraphrase. • some urls may have rotted since indexing. • a few entries below are placeholders for well-known works whose"},{"id":"studies-water-quality-sensing","title":"Related Studies — Water Quality, Limnology & Fish Kill Mechanisms","section":"research","sectionLabel":"Research Corpus","url":"files/studies-water-quality-sensing.html","provenance":"verified_external","flags":"","text":"studies-water-quality-sensing • related studies — water quality, limnology & fish kill mechanisms • 1.0.0 • 2026-07-17 • water_quality_sensing • verified_external • records derived from search-result summaries. open the sources before citing. • this collection contains the evidence that the problem is real, recurring, mechanistically understood, and specifically vertical. everything the omnidrone does at depth is justified from here. • seafdec-laguna-fishkill • water_quality_sensing • empirical_field • laguna de bay, philippines • investigation of the incidence and causes of mass fish kill in a shallow tropical eutrophic lake supporting extensive cage and pen culture. • fish kills implicated dissolved oxygen depletion, high ammonia-nitrogen, and hydrogen sulfide. • the lake is shallow, tro"},{"id":"studies-uav-remote-sensing","title":"Related Studies — UAV & Satellite Remote Sensing of Water","section":"research","sectionLabel":"Research Corpus","url":"files/studies-uav-remote-sensing.html","provenance":"verified_external","flags":"","text":"studies-uav-remote-sensing • related studies — uav & satellite remote sensing of water • 1.0.0 • 2026-07-17 • uav_remote_sensing • verified_external • all records derived from search-result summaries. open the sources before citing. see references-bibliography.json. • this is the theme where our contribution lives. the literature can map water quality from a drone; it cannot calibrate the map without a boat. that gap is the omnidrone's reason to exist, and this collection is the evidence that the gap is real. • mdpi-drones-inland-review-2024 • uav_remote_sensing • systematic_review • global • a global systematic review of drone-based remote sensing for monitoring water temperature, suspended solids, and cdom in inland waters, cataloguing challenges and opportunities across the published re"},{"id":"studies-harmful-algal-blooms","title":"Related Studies — Harmful Algal Blooms","section":"research","sectionLabel":"Research Corpus","url":"files/studies-harmful-algal-blooms.html","provenance":"verified_external","flags":"","text":"studies-harmful-algal-blooms • related studies — harmful algal blooms • 1.0.0 • 2026-07-17 • harmful_algal_blooms • verified_external • records derived from search-result summaries. open the sources before citing. • every study here measures pigments. none of them measure toxins. that gap is where lawsuits live and where people get poisoned, and this collection exists partly to keep the company honest about it. • mdpi-hab-meta-2021 • harmful_algal_blooms • meta_analysis • global • a meta-analysis of harmful algal bloom detection and monitoring from a remote sensing perspective, synthesising the methods and proxies used across the published record. • chlorophyll-a is the proxy used in approximately 80 percent of hab detection and monitoring studies. • chlorophyll-a is present in both toxic "},{"id":"studies-ai-ml-aquaculture","title":"Related Studies — AI & Machine Learning in Aquaculture","section":"research","sectionLabel":"Research Corpus","url":"files/studies-ai-ml-aquaculture.html","provenance":"verified_external","flags":"","text":"studies-ai-ml-aquaculture • related studies — ai & machine learning in aquaculture • 1.0.0 • 2026-07-17 • ai_ml_aquaculture • verified_external • records derived from search-result summaries. open the sources before citing. one entry in this collection (ai-aqua-review-2024) is not a verified publication and must be fixed or removed. • ai-aqua-review-2024 • ai_ml_aquaculture • systematic_review • review of machine learning, deep learning, attention mechanisms, and hybrid models applied to aquaculture — water quality monitoring, disease detection, feed optimisation, and fish behaviour analysis. • ml, dl, attention mechanisms, and hybrid models are driving gains across water quality, disease detection, feed optimisation, and behaviour analysis. • model accuracy depends on acquiring substantia"},{"id":"studies-digital-twin","title":"Related Studies — Digital Twins in Aquaculture","section":"research","sectionLabel":"Research Corpus","url":"files/studies-digital-twin.html","provenance":"verified_external","flags":"","text":"studies-digital-twin • related studies — digital twins in aquaculture • 1.0.0 • 2026-07-17 • digital_twin • verified_external • records derived from search-result summaries. open the sources before citing. • the digital twin is not our novelty. several exist. a thesis claiming to contribute an aquaculture digital twin will be told, correctly, that this ground is taken. our contribution is the observation architecture that feeds one. this collection exists to establish what already exists so we do not overclaim. • hamzah-dt-water-review-2024 • digital_twin • systematic_review • a systematic review of drone-based digital twins for water quality monitoring. • the closest prior art to this entire concept. a systematic review of exactly the intersection we occupy — drones, digital twins, water "},{"id":"studies-fish-health-disease","title":"Related Studies — Fish Health, Disease & Biosecurity","section":"research","sectionLabel":"Research Corpus","url":"files/studies-fish-health-disease.html","provenance":"verified_external","flags":"","text":"studies-fish-health-disease • related studies — fish health, disease & biosecurity • 1.0.0 • 2026-07-17 • fish_health_disease • verified_external • records derived from search-result summaries. open the sources before citing. • this collection sizes an enormous problem that the omnidrone barely touches. it is included because disease is a defining feature of the aquaculture landscape and any credible thesis must engage with it — and because the temptation to put a usd 6 billion figure on a slide and imply we address it is the single most dishonest move available to this company. this file exists partly to make that move impossible. • worldbank-disease-risk-2014 • fish_health_disease • policy_report • global • world bank discussion paper on reducing disease risk in aquaculture, synthesising"},{"id":"studies-feeding-nutrition","title":"Related Studies — Feeding, Nutrition & Feed Economics","section":"research","sectionLabel":"Research Corpus","url":"files/studies-feeding-nutrition.html","provenance":"verified_external","flags":"","text":"studies-feeding-nutrition • related studies — feeding, nutrition & feed economics • 1.0.0 • 2026-07-17 • feeding_nutrition • verified_external • records derived from search-result summaries. several sources in this collection are vendor or industry-association content with commercial interests in feed — noted per record. open the primary sources before citing. • feed is the only loss category in this repository where the value of an improvement can be computed from externally sourced numbers rather than from our own assumptions. that makes it the roi argument a sceptical buyer can check without trusting us — which is worth more than a bigger number they have to take on faith. • innovasea-fcr-guide • feeding_nutrition • policy_report • practitioner guide to improving feed conversion ratio i"},{"id":"studies-socioeconomic-adoption","title":"Related Studies — Socioeconomics & Technology Adoption","section":"research","sectionLabel":"Research Corpus","url":"files/studies-socioeconomic-adoption.html","provenance":"assumption","flags":"","text":"studies-socioeconomic-adoption • related studies — socioeconomics & technology adoption • 1.0.0 • 2026-07-17 • socioeconomic_adoption • assumption • low • this is the emptiest and most important collection in the research corpus, and the imbalance is diagnostic. • we have eight thematic collections. seven are populated with real studies about sensors, algorithms, twins, and fish. this one — about whether anyone will actually adopt, pay for, and keep using the technology — is nearly empty because we did not search for it properly. • the team's instinct was to research the technology, not the adoption. that instinct is exactly why aquaculture technology has a poor adoption record despite good technology. the engineering questions are tractable and interesting; the adoption questions are mess"},{"id":"research-gaps","title":"Research Gaps & Open Questions","section":"research","sectionLabel":"Research Corpus","url":"files/research-gaps.html","provenance":"derived_calculation","flags":"","text":"research-gaps • research gaps & open questions • 1.0.0 • 2026-07-17 • derived_calculation • everything this repository does not know, ranked by consequence. this is the file a thesis committee should read first and the file a founder should reread monthly. • ranked by 'if this answer comes back wrong, how much of the plan dies?' — not by how interesting the question is. the most consequential gaps are usually the most boring ones. • if any of these resolves badly, the venture as conceived does not work. all are answerable in phase 0 with phone calls and arithmetic — none require research. • gap-response-capacity • will a farmer act on a warning, or merely watch the loss arrive with better information? • the entire venture assumes information changes behaviour. if a warning arrives at 3 a.m"},{"id":"theoretical-framework","title":"Theoretical & Conceptual Framework","section":"research","sectionLabel":"Research Corpus","url":"files/theoretical-framework.html","provenance":"derived_calculation","flags":"","text":"theoretical-framework • theoretical & conceptual framework • 1.0.0 • 2026-07-17 • derived_calculation • the theory the study rests on. a thesis needs this chapter to explain why the intervention should work, not just what it does. without it, the work is engineering with citations attached. • mass mortality in intensive inland aquaculture is not primarily a water quality failure. it is an observability failure of a system whose dynamics are already understood. • limnologists have understood stratification and overturn for a century. the sensors exist and are affordable. the mechanism behind philippine lake kills — hypolimnetic water delivered to the surface, carrying its oxygen deficit, ammonia, and sulfide — is documented. nothing about the physics is mysterious. what is missing is somebo"},{"id":"methodology","title":"Research Methodology","section":"research","sectionLabel":"Research Corpus","url":"files/methodology.html","provenance":"design_target","flags":"","text":"methodology • research methodology • 1.0.0 • 2026-07-17 • design_target • how the study's claims will be tested. written before the data exists, so that the evaluation criteria are fixed before anyone has an incentive to move them. • pre-registering the method is the difference between a study and a rationalisation. once profiles start arriving, there will be enormous pressure to find the analysis that makes the product look good. this file exists to make that harder. • rq1 • can an aerial platform produce depth-resolved water quality profiles that agree with a boat-deployed reference sonde within a defined tolerance? • feasibility • if the answer is no, nothing else matters. this is the moment the core claim is either true or it is not. • h1: omnidrone profiles will agree with a reference"},{"id":"deployment-playbook","title":"Deployment Playbook","section":"operations","sectionLabel":"Operations & Safety","url":"files/deployment-playbook.html","provenance":"design_target","flags":"","text":"deployment-playbook • deployment playbook • 1.0.0 • 2026-07-17 • design_target • the operational runbook for taking a site from first contact to steady-state monitoring. written as a checklist because in the field, prose is not read and steps get skipped — and a skipped commissioning step becomes an incident. • a working fish farm is not a research site. the drone is the least important thing happening there on any given day. if an operation requires attention it will not get, it fails. every procedure below is written for a person with other jobs to do. • prospecting and qualification • do not deploy where we will lose. • response capacity • does the operator have aeration or other means to act on a warning? • a warning to a farm that cannot respond is a countdown clock, not a product. th"},{"id":"maintenance-schedule","title":"Maintenance Schedule","section":"operations","sectionLabel":"Operations & Safety","url":"files/maintenance-schedule.html","provenance":"design_target","flags":"","text":"maintenance-schedule • maintenance schedule • 1.0.0 • 2026-07-17 • design_target • intervals are design targets, not field-validated. a tropical, brackish, biologically active environment is harsh on hardware, and real intervals will likely be shorter than these until proven otherwise. corrosion and fouling do not respect the maintenance manual. • maintainable by a technician with hand tools, or it will not be maintained. • a distributed network of docks on remote lakeshores cannot each have an engineer. if a task needs a laptop, a calibration rig, or a specialist, it will be deferred until it becomes a failure. design maintenance for the person who is actually there. • the most dangerous maintenance lapse is the one that produces no visible symptom: a fouled sensor drifting, a dock batter"},{"id":"risk-register-fmea","title":"Risk Register & FMEA","section":"operations","sectionLabel":"Operations & Safety","url":"files/risk-register-fmea.html","provenance":"assumption","flags":"","text":"risk-register-fmea • risk register & fmea • 1.0.0 • 2026-07-17 • assumption • medium • fmea. rpn = severity x likelihood x detectability, each 1-10. higher rpn = higher priority. detectability: 1 = certain to be caught before harm, 10 = undetectable until harm occurs. • scores are the authors' engineering judgement, not measured failure rates. they are a prioritisation tool, not a probability claim. recompute after every design change and after every real incident. the value is in the ranking, not the absolute numbers. • the risks that kill ventures are rarely the dramatic ones. they are the ones with high severity and high detectability-difficulty — the failures nobody sees coming until the harm is done. this register is sorted to surface those, not the obvious ones. • r-01 • data_securit"},{"id":"training-certification","title":"Training & Certification","section":"operations","sectionLabel":"Operations & Safety","url":"files/training-certification.html","provenance":"design_target","flags":"","text":"training-certification • training & certification • 1.0.0 • 2026-07-17 • design_target • two audiences with completely different needs: the people who operate the system legally, and the people who use its output daily. conflating their training is how deployments fail. • commercial rpas operation and any aircraft over 7 kg require a caap rpa controller certificate. • caap-rpas-regulations • complete a caap-approved rpas course at an authorised training organisation. • pass the caap knowledge test (air law, meteorology, navigation, flight principles). • pass a practical flight demonstration under a caap evaluator. • typically five years, per public summaries — confirm with caap. • no certificate means no legal commercial flight. this is not something to schedule around; it is a preconditio"},{"id":"regulatory-framework","title":"Regulatory Framework","section":"compliance","sectionLabel":"Regulatory & Compliance","url":"files/regulatory-framework.html","provenance":"verified_external","flags":"","text":"regulatory-framework • regulatory framework • 1.0.0 • 2026-07-17 • verified_external • low • this is not legal advice. every regulatory statement below derives from secondary, search-result summaries of public rules, not from primary regulatory texts read in full. regulations change. the interpretations here may be wrong. before any regulatory claim enters an investor deck, a contract, or a design decision, obtain a written opinion from a qualified philippine aviation and fisheries lawyer and confirm current requirements directly with the agencies. building on this file as if it were authoritative would be a serious error. • this product sits at the intersection of three regulatory domains — aviation, fisheries, and (for medicine) veterinary — and each has a different agency, a different l"},{"id":"water-quality-standards","title":"Water Quality Standards & Thresholds","section":"compliance","sectionLabel":"Regulatory & Compliance","url":"files/water-quality-standards.html","provenance":"assumption","flags":"","text":"water-quality-standards • water quality standards & thresholds • 1.0.0 • 2026-07-17 • assumption • low • the numerical thresholds below are indicative placeholders drawn from general aquaculture practice. they have not been sourced to primary denr administrative orders or to species-specific primary literature. these numbers drive alert thresholds. an incorrect threshold here becomes a false 'all clear' or a false alarm in production, and a false all-clear can cost a harvest. this is the single highest-consequence set of placeholders in the entire repository. do not wire these into any alerting logic until they are replaced with sourced, species- and life-stage-specific values verified by an aquaculture scientist. • thresholds are species-specific and life-stage-specific. a fingerling and "},{"id":"biosecurity-protocol","title":"Biosecurity Protocol","section":"compliance","sectionLabel":"Regulatory & Compliance","url":"files/biosecurity-protocol.html","provenance":"design_target","flags":"","text":"biosecurity-protocol • biosecurity protocol • 1.0.0 • 2026-07-17 • design_target • medium • a drone whose probe visits pond a and then pond b is a pathogen vector with rotors. this is the single strongest technical objection to the multi-site concept, and it is answered here — in a protocol backed by hardware — or it is not answered at all. aquaculture disease losses run to roughly usd 6 billion annually; a monitoring product that spreads disease between the farms it monitors would be a catastrophic own-goal. • worldbank-disease-risk-2014 • the sonde • high • it is immersed in the culture water of every site it visits. the primary vector. • the tether • high • also immersed, over its full deployed length, and routinely forgotten. wiping the sonde while reeling in a contaminated tether acco"},{"id":"ethics-data-privacy","title":"Ethics, Data Privacy & Responsible Use","section":"compliance","sectionLabel":"Regulatory & Compliance","url":"files/ethics-data-privacy.html","provenance":"design_target","flags":"","text":"ethics-data-privacy • ethics, data privacy & responsible use • 1.0.0 • 2026-07-17 • design_target • a platform that flies cameras over shared water, holds sensitive farm data, dispenses substances, and could be turned to surveillance carries real ethical weight. these are not compliance checkboxes; several of them are places where the company could do genuine harm, and a couple are places where the technology's second-order effects run against its stated purpose. this file names them plainly. • the farmer's data belongs to the farmer. we are custodians, not owners. • it rules out the data-monetisation business models an investor will inevitably suggest — selling aggregated farm data, or building a proprietary dataset the farmer cannot take with them. those models are available and lucrativ"},{"id":"business-model-canvas","title":"Business Model Canvas","section":"business","sectionLabel":"Business Model","url":"files/business-model-canvas.html","provenance":"modeled_projection","flags":"","text":"business-model-canvas • business model canvas • 1.0.0 • 2026-07-17 • modeled_projection • low • osterwalder-bmc-2010 • the nine-block canvas, filled honestly. where a block rests on an untested assumption, it says so. a canvas full of confident assertions at trl 3 is a work of fiction; this one flags its fictions. • commercial lake-cage and pond aquaculture operators with response capacity (aeration) and a budget line. • cooperatives aggregating smallholders; bfar/lgu as programme buyers. • individual smallholders — the greatest need, no direct affordability. reached via cooperatives or public programmes, not direct sales. • response capacity, not scale. see customer-personas.json#/segmentation_logic. • that this segment exists in sufficient density on the target lakes and will pay. untest"},{"id":"pricing-revenue","title":"Pricing & Revenue Model","section":"business","sectionLabel":"Business Model","url":"files/pricing-revenue.html","provenance":"modeled_projection","flags":"","text":"pricing-revenue • pricing & revenue model • 1.0.0 • 2026-07-17 • modeled_projection • speculative • there are no prices in this file, and that is deliberate. pricing requires knowing the cost to serve (a bom with zero real quotes), the value delivered (unproven), and willingness to pay (unmeasured). inventing a subscription price now would produce a number that flows into the financial model and the funding ask and is wrong at the root. this file gives the pricing logic and the inputs required, so a real price can be set the moment phase 0 supplies them. a founder who says 'here is how we will price and here is what we need to know first' is more credible than one who presents a confident price built on nothing. • price against value delivered, not cost incurred — but anchor on the value t"},{"id":"unit-economics","title":"Unit Economics","section":"business","sectionLabel":"Business Model","url":"files/unit-economics.html","provenance":"modeled_projection","flags":"","text":"unit-economics • unit economics • 1.0.0 • 2026-07-17 • modeled_projection • speculative • this file contains no unit economics numbers. it contains the model and the drivers. the reason is stated bluntly: the cost side rests on a bom with zero real supplier quotes and a maintenance burden that is estimated rather than measured, and the revenue side rests on a price that cannot be set until phase 0. multiplying two unknowns produces a confident-looking contribution margin that is wrong at the root, and every downstream financial figure inherits the error. what follows is the structure, so that real numbers slot in cleanly and so a reviewer can see exactly which inputs are missing. this honesty is itself the deliverable at trl 3. • one dock serving its cluster of stations. • coverage, cost, "},{"id":"financial-projections","title":"Financial Projections","section":"business","sectionLabel":"Business Model","url":"files/financial-projections.html","provenance":"modeled_projection","flags":"","text":"financial-projections • financial projections • 1.0.0 • 2026-07-17 • modeled_projection • speculative • this file deliberately contains no revenue forecast, no hockey-stick chart, and no five-year p&l. producing one at trl 3, with no price, no cost, no customer, and no validated product, would be an act of creative writing dressed as finance. every professional investor has seen the fabricated hockey-stick a thousand times and discounts it to zero. what this file provides instead is: the spend plan (which we can estimate), the milestones that unlock the next tranche, and the scenario structure for revenue once the inputs exist. a credible early-stage financial story is a spend plan tied to de-risking milestones — not a revenue fantasy. • at this stage, costs are estimable and revenues are "},{"id":"funding-ask","title":"Funding Ask","section":"business","sectionLabel":"Business Model","url":"files/funding-ask.html","provenance":"modeled_projection","flags":"","text":"funding-ask • funding ask • 1.0.0 • 2026-07-17 • modeled_projection • low • no dollar amount appears here because the amount depends on team size and hardware costs that phase 0 determines. what appears is the structure of the ask, the use of funds, and — most importantly — the milestone each tranche unlocks. fill the amount in after phase 0. • raise in tranches against de-risking milestones, not a lump against a revenue projection. • this is a hardware company with a real validation timeline and three untested load-bearing assumptions. the credible structure is: a small first raise to test the cheapest, most fundamental assumptions, then larger raises unlocked by evidence. an investor is buying successive risk reduction. • we are not asking you to believe a forecast. we are asking you to "},{"id":"go-to-market","title":"Go-to-Market Strategy","section":"business","sectionLabel":"Business Model","url":"files/go-to-market.html","provenance":"modeled_projection","flags":"","text":"go-to-market • go-to-market strategy • 1.0.0 • 2026-07-17 • modeled_projection • low • moore-crossing-chasm-1991 • rogers-diffusion-2003 • this is not a product sale. it is a coalition assembly. • for a single deployment, five different constituencies must each say yes for a different reason: the farm manager (roi), the technician (not surveillance), the lgu (permit), caap (airspace), and the person who owns the shore (tenure). see stakeholder-pain-points.json#/the_alignment_problem. a gtm plan that models this as 'generate leads, close deals' has not understood the sector, and it will fail in the way aquaculture technology usually fails. • sales cycles are long and relationship-led. the unit of go-to-market is a lake — its coalition, its cooperative, its lgu — not a farm. win a lake's coa"},{"id":"traction","title":"Traction","section":"business","sectionLabel":"Business Model","url":"files/traction.html","provenance":"verified_external","flags":"","text":"traction • traction • 1.0.0 • 2026-07-17 • verified_external • high • this file is empty of traction because there is none, and that emptiness is a deliberate act of integrity, not an oversight. • it would be trivial to populate this file with invented pilot agreements, fabricated letters of intent, imaginary customer counts, or a 'we are in discussions with' list that overstates a single polite email. many pitch decks do exactly this. • a pitch that invents traction is fraud, and it is the specific kind of fraud that diligence is designed to catch. a single fabricated loi that an investor calls to verify ends the raise and the reputation. a pitch that shows honest zeros against a rigorous plan survives diligence and builds the trust that the unverifiable later claims depend on. see fundin"},{"id":"sdg-alignment","title":"UN Sustainable Development Goal Alignment","section":"impact","sectionLabel":"Impact","url":"files/sdg-alignment.html","provenance":"assumption","flags":"","text":"sdg-alignment • un sustainable development goal alignment • 1.0.0 • 2026-07-17 • assumption • sdg alignment is easy to overclaim — every startup maps itself to half the goals. this file distinguishes goals the product genuinely and directly serves from ones it touches tangentially, and it flags where the product's second-order effects could run against a goal. an honest sdg map includes the tensions. • zero hunger • 2.4 — sustainable food production systems and resilient agricultural practices • strong • aquatic food is a major and growing protein source; reducing losses and improving yield in aquaculture directly increases food availability. aquaculture is now the majority of aquatic animal production. • fao-sofia-2024 • the contribution is real but bounded by our addressable fraction of "},{"id":"environmental-impact","title":"Environmental Impact Assessment","section":"impact","sectionLabel":"Impact","url":"files/environmental-impact.html","provenance":"assumption","flags":"","text":"environmental-impact • environmental impact assessment • 1.0.0 • 2026-07-17 • assumption • low • a product sold on environmental stewardship must account for its own footprint, honestly, including the harms. an environmental impact section that lists only benefits is not an assessment; it is an advertisement. • reduced eutrophication of shared water bodies • condition-aware feeding reduces uneaten feed, the primary driver of the nutrient loading that degrades the water. carrying-capacity analytics support collective management. • fao-nutrient-dynamics-eutrophic • ija-environmental-impacts-ph • potentially significant, unproven. depends on farms actually feeding on evidence and on carrying-capacity analytics being adopted. • undercut by the over-stocking paradox — the same instruments could"},{"id":"social-economic-impact","title":"Social & Economic Impact","section":"impact","sectionLabel":"Impact","url":"files/social-economic-impact.html","provenance":"assumption","flags":"","text":"social-economic-impact • social & economic impact • 1.0.0 • 2026-07-17 • assumption • low • impact claims are hypotheses until measured. this file states the mechanisms and, for each, what evidence would be needed to substantiate it. an impact claim without a measurement plan is aspiration. • reduced catastrophic income volatility for aquaculture households • earlier warning and response capacity reduce the frequency or severity of harvest-destroying kill events. • operators — most acutely smallholders, for whom a kill is existential. • inquirer-taal-fishkill-2023 • pna-tilapia-fishkill • a matched comparison of income volatility between monitored and unmonitored farms across multiple cycles. see methodology.json — this is the load-bearing rq5. • directly limited by the affordability parad"},{"id":"kpi-definitions","title":"KPI Definitions","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/kpi-definitions.html","provenance":"","flags":"A","text":"kpi-definitions • kpi definitions • 1.0.0 • 2026-07-17 • every kpi the system and the business track, with a precise operational definition. conforms to schema-registry.json#/definitions/kpi. the definition is the point — if two people can compute different numbers from it, it is not finished. • each kpi has a `status`: measured (from real data), modeled (from a projection), target_only (a goal with no baseline), or awaiting_data (defined but empty). at trl 3, almost everything is target_only or awaiting_data — and saying so is the honest thing. a dashboard of confident kpis with no data behind them is theatre. • kpi-survival-rate • survival rate • proportion of stocked individuals harvested alive, per unit per cycle. • harvested_count / stocked_count • % • higher_is_better • awaiting_data"},{"id":"sample-telemetry","title":"Sample Telemetry — ILLUSTRATIVE SYNTHETIC DATA","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/sample-telemetry.html","provenance":"illustrative_synthetic","flags":"S","text":"sample-telemetry • sample telemetry — illustrative synthetic data • 1.0.0 • 2026-07-17 • illustrative_synthetic • every number in this file is fabricated. it describes no real pond, no real fish, and no real sortie. • this data exists for one reason: so the webpage developer has correctly-shaped records to build and test the dashboard and twin against, before real data exists. it shows the shape of the data, not any fact about the world. • this data must never appear in a thesis results chapter, a pitch as evidence, or any context implying it is real. the webpage must render the illustrative_synthetic badge (see brand-identity.json) prominently on anything derived from it. if this data is ever mistaken for real, the integrity of the entire repository is compromised. • hand-constructed to b"},{"id":"sample-pond-twin-state","title":"Sample Digital Twin State — ILLUSTRATIVE SYNTHETIC DATA","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/sample-pond-twin-state.html","provenance":"illustrative_synthetic","flags":"S","text":"sample-pond-twin-state • sample digital twin state — illustrative synthetic data • 1.0.0 • 2026-07-17 • illustrative_synthetic • every value in this file is fabricated. it describes no real pond. it exists solely so the webpage developer can build and test the pondtwin 3d visualisation against correctly-shaped data. it must never appear as evidence of anything. the webpage must render the illustrative_synthetic badge on the entire twin view when fed this file. • synth-lake-01 • fictional timestamp • a fabricated simple geometry for rendering. not a real bathymetry. • rectangular demo bay • synth-c1 • tilapia • nominal • synth-c2 • tilapia • nominal • synth-c3 • tilapia • advisory • synth-c4 • tilapia • warning • synth-c5 • milkfish • warning • synth-st-01 • synth-st-04 • synth-st-05 • this"},{"id":"chart-global-production","title":"The Inflection: Aquaculture Overtakes Capture Fisheries","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-global-production.html","provenance":"verified_external","flags":"","text":"chart-global-production • grouped_bar • the inflection: aquaculture overtakes capture fisheries • global aquatic animal production, 2022 • in 2022, for the first time, aquaculture produced more aquatic animals than capture fisheries — 51 percent of the total. this is the structural shift that makes aquaculture technology a category. capture fisheries cannot be sensor-optimised; farmed systems can. • verified_external • fao-sofia-2024 • source • category • production • million tonnes • linear • aquatic animal production 2022 • million tonnes • verified_external • aquaculture • 51% of total — first time above capture • capture fisheries • approximate; total aquatic animal production 185.4 mt • point_label • aquaculture: 94.4 mt (51%) • info • capture figure derived: aquaculture 94.4 mt at 51"},{"id":"chart-problem-cost-breakdown","title":"The Structure of Aquaculture Losses","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-problem-cost-breakdown.html","provenance":"modeled_projection","flags":"","text":"chart-problem-cost-breakdown • table • the structure of aquaculture losses • visibility versus addressability — not a peso breakdown • deliberately rendered as a structured matrix, not a pie chart. a pie of peso values would imply we know the proportions, and we do not. what we do know is which loss categories are visible versus hidden, and which the omnidrone addresses versus does not. the most important cell may be the invisible-and-addressable one: chronic sub-lethal loss, which is unmeasured, possibly the largest, and squarely in our capability. • modeled_projection • inquirer-taal-fishkill-2023 • pna-tilapia-fishkill • innovasea-fcr-guide • worldbank-disease-risk-2014 • fao-nutrient-dynamics-eutrophic • loss category • visibility • addressable by omnidrone • evidence provenance • cata"},{"id":"chart-market-sizing","title":"Market Sizing — Method, Not Number","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-market-sizing.html","provenance":"modeled_projection","flags":"","text":"chart-market-sizing • funnel • market sizing — method, not number • the tam/sam/som funnel and the inputs we are missing • this is deliberately not a set of concentric circles with dollar figures. a defensible market size needs operator counts, size distributions, and willingness-to-pay data we do not yet have. this funnel shows the method and marks each stage with the specific input required to fill it. a founder who shows the method and names the missing input is more credible than one who presents a fabricated number. • modeled_projection • fao-sofia-2024 • market definition funnel • modeled_projection • tam — all aquaculture operations • operators • global operator counts by system type • not computed • do not use the usd 312.8bn industry output as tam — that is the value of the fish, "},{"id":"chart-do-diel-cycle","title":"Why Sampling Time Decides What You See","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-do-diel-cycle.html","provenance":"illustrative_synthetic","flags":"S","text":"chart-do-diel-cycle • line • why sampling time decides what you see • the diel dissolved oxygen cycle over 24 hours • dissolved oxygen peaks in mid-afternoon and bottoms out just before dawn. a manual sample at 9 a.m. reads a safe 6.4 mg/l; the 5 a.m. minimum on the same day is 2.8 mg/l — acute stress. this is the diel sampling bias, and it is the entire argument for autonomous pre-dawn monitoring. • illustrative_synthetic • this curve is fabricated. it is physically plausible but describes no real pond. it illustrates the mechanism. the webpage must show the illustrative_synthetic badge. replace with real telemetry at v2.0.0. • boyd-water-quality-2020 • hour of day • h • linear • dissolved oxygen • mg/l • linear • surface do (0.5 m) — synthetic • mg/l • illustrative_synthetic • hline • su"},{"id":"chart-do-depth-profile","title":"The Loaded Gun: What a Vertical Profile Reveals","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-do-depth-profile.html","provenance":"illustrative_synthetic","flags":"S","text":"chart-do-depth-profile • line • the loaded gun: what a vertical profile reveals • dissolved oxygen and temperature versus depth, pre-dawn • a stratified water column with a survivable surface (3.1 mg/l) hiding anoxic, sulfide-generating bottom water (0.2 mg/l, negative orp) below the thermocline at ~3.5 m. a surface sensor sees nothing wrong. a cold rain that mixes this column delivers the bottom water to the fish — the exact mechanism in the laguna de bay fish-kill literature. depth is where the killing happens, and only a profile can see it. • illustrative_synthetic • fabricated but physically plausible profile. describes no real station. illustrates the stratification mechanism. webpage must badge as illustrative_synthetic. • seafdec-laguna-fishkill • idso-schmidt-stability-1973 • value"},{"id":"chart-financial-projection","title":"Spend Plan by Phase — Not a Revenue Forecast","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-financial-projection.html","provenance":"modeled_projection","flags":"","text":"chart-financial-projection • waterfall • spend plan by phase — not a revenue forecast • milestone-gated use of funds through validation • this is deliberately a spend plan gated by de-risking milestones, not a hockey-stick revenue projection. at trl 3 with no price, no cost, and no customer, a revenue forecast would be fiction. what can be honestly shown is the shape of the spend — cheap first, expensive validation season — and the milestone each phase unlocks. a serious investor prefers this to a fabricated up-and-to-the-right curve. • modeled_projection • phase • category • relative spend envelope • qualitative • category • spend envelope by phase (relative, not absolute) • modeled_projection • no dollar amounts — they depend on phase 0 outputs (team size, hardware costs). relative envel"},{"id":"chart-manual-vs-omnidrone","title":"Monitoring Approaches Compared","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-manual-vs-omnidrone.html","provenance":"design_target","flags":"","text":"chart-manual-vs-omnidrone • radar • monitoring approaches compared • omnidrone against the real alternatives — honest scoring • a capability comparison across the approaches a farm actually chooses between. the omnidrone wins on depth, coverage, and imaging; it loses on continuity, weather tolerance, cost, and regulatory simplicity. an honest radar shows the losses. the takeaway is not that we dominate — it is that a fixed-buoy + omnidrone hybrid dominates either alone, which is where the product roadmap points. • design_target • scores are the authors' qualitative judgement on a 1-5 scale, not measured benchmarks. a vendor-scored comparison always flatters the vendor; this one deliberately scores our own weaknesses low so the comparison is credible. see competitive-landscape.json. • depth"},{"id":"chart-species-production-mix","title":"Where Farmed Aquatic Animals Are Produced","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-species-production-mix.html","provenance":"verified_external","flags":"A","text":"chart-species-production-mix • donut • where farmed aquatic animals are produced • by region and by system, 2022 • two facts that justify the beachhead: 70 percent of production is in asia, and 62.6 percent of farmed aquatic animals come from inland systems — precisely the omnidrone's environment. building for tropical inland asian aquaculture is building for the centre of the industry. • verified_external • fao-sofia-2024 • regional share of aquatic animal output 2022 • % • verified_external • asia • europe • latin america & caribbean • africa • northern america • oceania • inland vs marine/coastal share of farmed aquatic animals • verified_external • inland • marine & coastal • render as a second donut. inland dominance is the argument for an aerial platform designed for lakes and ponds "},{"id":"chart-tech-readiness","title":"Technology Readiness — Where We Actually Are","section":"datasets","sectionLabel":"Datasets & Charts","url":"files/chart-tech-readiness.html","provenance":"modeled_projection","flags":"","text":"chart-tech-readiness • line • technology readiness — where we actually are • trl progression with gate criteria, not calendar dates • the development roadmap as a trl progression, gated by evidence rather than dates. the company is at trl 3 today — analytical proof of concept, nothing flown. each step up is unlocked by a specific piece of evidence, and two gates carry explicit kill criteria. rendering this against evidence-gates rather than a gantt calendar is deliberate: a hardware timeline stated in dates the team cannot honour destroys credibility. • modeled_projection • nasa-trl • phase • category • technology readiness level • trl • linear • trl progression • modeled_projection • now (phase 0) • analytical/experimental proof of concept. physics established in literature; integration n"},{"id":"pitch-deck-outline","title":"Pitch Deck Outline","section":"pitch","sectionLabel":"Pitch & Thesis Kit","url":"files/pitch-deck-outline.html","provenance":"design_target","flags":"","text":"pitch-deck-outline • pitch deck outline • 1.0.0 • 2026-07-17 • design_target • a slide-by-slide outline for the investor deck, pulling from across the repository. built on the wager stated throughout: rigorous honesty is more fundable than polished optimism, for the right investor. each slide names its source file and the one thing it must accomplish. • lead with the inflection, sell the checkable roi, volunteer the risks, and never overclaim the predictive capability. • this industry just became the majority of the world's aquatic animal production → its operators are blind to the thing that kills their stock → the blindness is economic, not technical → an aerial platform inverts that economics → here is the one thing we must prove and how we'll prove it cheaply → here is the boring roi t"},{"id":"elevator-pitches","title":"Elevator Pitches","section":"pitch","sectionLabel":"Pitch & Thesis Kit","url":"files/elevator-pitches.html","provenance":"design_target","flags":"","text":"elevator-pitches • elevator pitches • 1.0.0 • 2026-07-17 • design_target • the same argument at four lengths and for different audiences. all honest — none claims a flown product or a validated prediction. • we make the water legible to the people who farm it — an autonomous drone that profiles a fish farm's water at depth, several times a day, and warns the farmer before the fish die. • the first sentence to anyone. • aquaculture just became the majority of the world's aquatic animal production, and its operators are flying blind — they find out their water has gone bad when the fish are already floating. the omnidrone flies over the farm, drops a probe to measure the water column at depth, and turns that into a warning early enough to act on. we're building the observability layer for an"},{"id":"faq-objections","title":"FAQ & Objection Handling","section":"pitch","sectionLabel":"Pitch & Thesis Kit","url":"files/faq-objections.html","provenance":"design_target","flags":"","text":"faq-objections • faq & objection handling • 1.0.0 • 2026-07-17 • design_target • the hard questions, with honest answers. an objection-handling document that only contains softballs is useless. these are the questions that actually get asked, ranked roughly by how often and how sharply. the answers concede what is true and defend what is defensible — because a defended overclaim is worse than a conceded weakness. • why does this need to fly? a robotic boat has better endurance and no aviation regulator. • highest — this is the sharpest technical objection • a usv genuinely beats us on endurance and weather tolerance, and for some customers it's the right answer — we'll say so. our advantages are three: transit speed across many stations (a boat crawls; we cover a lake array fast), simultan"},{"id":"thesis-outline","title":"Thesis / Dissertation Outline","section":"pitch","sectionLabel":"Pitch & Thesis Kit","url":"files/thesis-outline.html","provenance":"design_target","flags":"","text":"thesis-outline • thesis / dissertation outline • 1.0.0 • 2026-07-17 • design_target • a chapter structure for an engineering/technology thesis on the omnidrone concept, mapped to the repository files that supply each chapter. written for a design-and-feasibility thesis (which is what trl 3 supports), with a clear path to a results-bearing thesis once validation data exists. • a design, specification, and feasibility study with a pre-registered validation methodology. it contributes a problem analysis, a system architecture, an identified research gap, and a testable plan. it does not contribute empirical results, because none exist. • an empirical thesis once phase 2-3 data exists — the profile-vs-reference agreement, the calibration-uncertainty curve, and the stratification-precursor anal"}];
